import React, { useEffect, useState, useRef } from "react";
import {
  TrendingUp,
  Users,
  Activity,
  DollarSign,
  Package,
  BarChart3,
  Zap,
  CheckCircle2,
  Clock,
  RefreshCw,
  ShoppingBag,
  ArrowUpRight,
} from "lucide-react";
import { Column } from "@ant-design/plots";
import { Table, Select, Avatar } from "antd";
import { useDispatch, useSelector } from "react-redux";
import {
  getMonthlyData,
  getOrders,
  getYearlyData,
} from "../features/auth/authSlice";
import { getProducts } from "../features/product/productSlice";
import { config } from "../utils/axiosconfig";
import { getSocket } from "../socket";



const Dashboard = () => {
  const dispatch = useDispatch();
  const [loading, setLoading] = useState(true);
  const [lastRefreshed, setLastRefreshed] = useState(new Date());
  const intervalRef = useRef(null);

  const fetchAllData = () => {
    setLoading(true);
    // Dispatching individually to prevent blocking the whole UI if one request is slow
    dispatch(getMonthlyData(config));
    dispatch(getYearlyData(config));
    dispatch(getOrders(config));
    dispatch(getProducts()).then(() => setLoading(false));
    setLastRefreshed(new Date());
  };

  useEffect(() => {
    fetchAllData();
    intervalRef.current = setInterval(() => {
      dispatch(getMonthlyData(config));
      dispatch(getYearlyData(config));
      dispatch(getOrders(config));
      dispatch(getProducts());
      setLastRefreshed(new Date());
    }, 45000); // refresh every 45s

    const socket = getSocket();
    const handleRefresh = () => fetchAllData();
    if (socket) socket.on("dashboard:refresh", handleRefresh);

    return () => {
      clearInterval(intervalRef.current);
      if (socket) socket.off("dashboard:refresh", handleRefresh);
    };
  }, [dispatch]);

  const monthlyDataState = useSelector((state) => state?.auth?.monthlyData);
  const yearlyDataState = useSelector((state) => state?.auth?.yearlyData);
  const orderState = useSelector((state) => state?.auth?.orders.orders);
  const productState = useSelector((state) => state?.product?.products);

  const totalProducts = productState?.length || 0;
  const inStockProducts = productState?.filter((p) => p.quantity > 0)?.length || 0;
  const uniqueCustomers = orderState ? new Set(orderState.map((o) => o?.user?.id || o?.user?._id).filter(Boolean)).size : 0;

  const dataMonthly = monthlyDataState?.map((item) => ({
    type: item?._id?.month || item?.month,
    income: item?.amount,
  })) || [];


  const commonChartConfig = {
    xField: "type",
    padding: "auto",
    label: { position: "middle", style: { fill: "#FFFFFF", opacity: 0.6, fontSize: 12, fontWeight: 700 } },
    columnStyle: { radius: [10, 10, 0, 0] },
    xAxis: { label: { style: { fill: "#64748b", fontSize: 11, fontWeight: 700 } } },
    yAxis: { label: { style: { fill: "#64748b", fontSize: 11, fontWeight: 700 } } },
  };

  const columns = [
    {
      title: "Order ID",
      dataIndex: "rank",
      render: (text) => (
        <span className="font-mono text-[11px] font-black text-blue-600 bg-blue-50 px-2 py-1 rounded-lg border border-blue-100 uppercase">
          #{text?.slice(-6) || "------"}
        </span>
      ),

    },
    {
      title: "Patient / Client",
      dataIndex: "name",
      render: (text) => (
        <div className="flex items-center gap-3">
          <Avatar size={34} src={`https://api.dicebear.com/7.x/initials/svg?seed=${text}&backgroundColor=f1f5f9&textColor=0f172a`} className="rounded-xl border border-slate-100 shadow-sm" />
          <span className="font-bold text-slate-800 text-[14px]">{text}</span>
        </div>
      ),
    },
    {
      title: "Revenue",
      dataIndex: "dprice",
      render: (text) => <span className="font-black text-slate-900">{text?.toLocaleString()} <span className="text-[10px] text-slate-400">ETB</span></span>,
    },
    {
      title: "Status",
      dataIndex: "status",
      render: (status) => (
        <div className={`status-badge ${status === "Delivered" ? "success" : "info"}`}>
          <div className={`w-1.5 h-1.5 rounded-full ${status === "Delivered" ? "bg-emerald-500" : "bg-blue-500"}`} />
          {status}
        </div>
      ),
    },
  ];

  const data1 = orderState?.slice(0, 6).map((order, i) => ({
    key: i,
    rank: order?.id || order?._id,
    name: (order?.user?.firstname || order?.firstName || "Walk-in") + " " + (order?.user?.lastname || order?.lastName || "Patient"),
    status: order?.status || order?.orderStatus,
    dprice: order?.totalPrice,
  })) || [];


  return (
    <div className="dashboard-wrapper">


      {/* Hero Header Section */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
        <div className="space-y-1">
          <div className="flex items-center gap-2 mb-2">
            <div className="h-1 w-8 bg-blue-600 rounded-full" />
            <span className="text-[11px] font-black text-blue-600 uppercase tracking-[0.2em]">Management Overview</span>
          </div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Console<span className="text-blue-600">.</span></h1>
          <p className="text-[15px] text-slate-400 font-bold">Health system analytics and real-time operations.</p>
        </div>
        
        <div className="flex items-center gap-4">
          <div className="bg-white p-2 rounded-2xl border border-slate-100 flex items-center gap-4 shadow-sm">
             <div className="flex items-center gap-2 px-3 py-1.5 bg-emerald-50 text-emerald-600 rounded-xl text-[12px] font-black border border-emerald-100/50">
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
                SYSTEM LIVE
             </div>
             <button onClick={fetchAllData} disabled={loading} className="p-2 text-slate-400 hover:text-blue-600 transition-colors">
                <RefreshCw size={20} className={loading ? "animate-spin" : ""} />
             </button>
          </div>
        </div>
      </div>

      {/* Smart KPI Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-10">
        {[
          { label: "Total Revenue", val: yearlyDataState?.[0]?.amount?.toLocaleString(), unit: "ETB", icon: <DollarSign size={24}/>, color: "blue", trend: "+12.5%" },
          { label: "Active Orders",  val: orderState?.length || 0, unit: "Orders", icon: <ShoppingBag size={24}/>, color: "indigo", trend: "+8.2%" },
          { label: "Patient Base", val: uniqueCustomers, unit: "Total", icon: <Users size={24}/>, color: "emerald", trend: "+2.4%" },
          { label: "Catalog Size", val: totalProducts, unit: "SKUs", icon: <Package size={24}/>, color: "amber", trend: "Inventory" },
        ].map((k, i) => (
          <div className="kpi-card-premium relative group overflow-hidden" key={i}>
            <div className="flex justify-between items-start relative z-10">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center bg-${k.color}-50 text-${k.color}-600 group-hover:scale-110 transition-transform duration-500`}>
                {k.icon}
              </div>
              <span className={`text-[11px] font-black px-2.5 py-1 rounded-lg ${k.trend.includes('+') ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-50 text-slate-400'}`}>
                {k.trend}
              </span>
            </div>
            <div className="mt-6 relative z-10">
              <p className="text-[12px] font-black text-slate-400 uppercase tracking-widest mb-1">{k.label}</p>
              <div className="flex items-baseline gap-2">
                <span className="text-3xl font-black text-slate-900 tracking-tight">{loading ? "..." : k.val}</span>
                <span className="text-[12px] font-bold text-slate-400 uppercase tracking-tighter">{k.unit}</span>
              </div>
            </div>
            {/* Background Accent */}
            <div className={`absolute -right-4 -bottom-4 w-24 h-24 bg-${k.color}-50 rounded-full blur-2xl opacity-0 group-hover:opacity-100 transition-opacity`} />
          </div>
        ))}
      </div>

      {/* Main Insights Area */}
      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
        {/* Performance Chart */}
        <div className="xl:col-span-2 enterprise-card p-8 bg-white border border-slate-100">
          <div className="flex justify-between items-center mb-10">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-xl bg-blue-50 text-blue-600 flex items-center justify-center">
                <TrendingUp size={20} />
              </div>
              <h3 className="text-[18px] font-black text-slate-900">Revenue Performance</h3>
            </div>
            <Select defaultValue="monthly" variant="borderless" className="font-bold text-slate-400" />
          </div>
          <div className="h-[340px] px-2">
            {dataMonthly.length > 0 ? (
              <Column {...{ ...commonChartConfig, data: dataMonthly, yField: "income", color: "#2563eb" }} />
            ) : (
              <div className="h-full flex flex-col items-center justify-center opacity-30">
                <Activity size={48} className="text-slate-200 mb-4"/>
                <p className="text-sm font-black uppercase tracking-widest">Collecting Data...</p>
              </div>
            )}
          </div>
        </div>

        {/* Recent Transactions */}
        <div className="enterprise-card p-8 bg-white border border-slate-100">
          <div className="flex justify-between items-center mb-8">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-xl bg-slate-50 text-slate-600 flex items-center justify-center">
                <Activity size={20} />
              </div>
              <h3 className="text-[18px] font-black text-slate-900">Recent Stream</h3>
            </div>
          </div>
          <div className="space-y-6">
             {data1.map((order) => (
               <div key={order.key} className="flex items-center justify-between p-3 rounded-2xl hover:bg-slate-50/50 transition-all border border-transparent hover:border-slate-100 group">
                  <div className="flex items-center gap-4">
                    <Avatar size={40} className="rounded-xl border-2 border-white shadow-sm ring-1 ring-slate-100" src={`https://api.dicebear.com/7.x/initials/svg?seed=${order.name}`} />
                    <div>
                      <p className="text-[14px] font-black text-slate-900 mb-0.5 leading-none">{order.name}</p>
                      <p className="text-[11px] text-slate-400 font-bold uppercase tracking-widest">#{order.rank?.slice(-6) || "------"}</p>

                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[14px] font-black text-slate-900 mb-0.5 leading-none">{order.dprice.toLocaleString()} ETB</p>
                    <span className={`text-[10px] font-black uppercase tracking-widest ${order.status === 'Delivered' ? 'text-emerald-500' : 'text-blue-500'}`}>
                       {order.status}
                    </span>
                  </div>
               </div>
             ))}
             <button className="w-full mt-4 py-3 bg-slate-50 text-slate-400 font-black text-[11px] uppercase tracking-[0.2em] rounded-xl hover:bg-blue-50 hover:text-blue-600 transition-all">
                Access All Records
             </button>
          </div>
        </div>
      </div>

      {/* System Footer Info */}
      <div className="mt-12 flex flex-col sm:flex-row items-center justify-between gap-6 border-t border-slate-100 pt-10 pb-6 opacity-60">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-lg bg-slate-900 flex items-center justify-center text-white">
            <Zap size={14} fill="white" strokeWidth={0} />
          </div>
          <p className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Pulse Addis Operations OS v4.0</p>
        </div>
        <div className="flex items-center gap-6">
          <span className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Privacy</span>
          <span className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Security</span>
          <span className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Support</span>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
